class Slidezy{constructor(selector,options={}){this.container=document.querySelector(selector);if(!this.container){console.error(`Element with selector "${selector}" not found.`);return}this.options=Object.assign({slideDuration:3e3,transitionDuration:500,autoplay:true,loop:true,items:1,step:null},options);if(this.options.step===null){this.options.step=this.options.items}this.index=0;this.timer=null;this.isAnimating=false;this.dotHandlers=[];this._createBuild();this._cacheElements();this._init()}_createBuild(){this.container.classList.add("slidezy");const content=document.createElement("div");content.classList.add("slidezy-content");const track=document.createElement("div");track.classList.add("slidezy-track");const slides=Array.from(this.container.children);slides.forEach(slide=>{slide.classList.add("slidezy-slide");track.appendChild(slide)});this.container.replaceChildren(content);content.appendChild(track);this.container.appendChild(content);const prevBtn=document.createElement("button");prevBtn.classList.add("slidezy-prev");prevBtn.innerHTML="&#10094;";const nextBtn=document.createElement("button");nextBtn.classList.add("slidezy-next");nextBtn.innerHTML="&#10095;";content.appendChild(prevBtn);content.appendChild(nextBtn);const dotsContainer=document.createElement("div");dotsContainer.classList.add("slidezy-nav");const totalSlides=Math.max(slides.length-this.options.items+1,1);for(let i=0;i<totalSlides;i++){const dot=document.createElement("span");dot.classList.add("slidezy-dot");if(i===0)dot.classList.add("active");dotsContainer.appendChild(dot)}this.container.appendChild(dotsContainer)}_cacheElements(){this.track=this.container.querySelector(".slidezy-track");this.slides=this.container.querySelectorAll(".slidezy-slide");this.options.items=Math.min(this.options.items,this.slides.length);this.prevBtn=this.container.querySelector(".slidezy-prev");this.nextBtn=this.container.querySelector(".slidezy-next");this.dots=this.container.querySelectorAll(".slidezy-dot")}_init(){if(this.options.loop){this._setupCloneSlides();this.index=this.options.items}this._setSlidesStyle();this.track.style.transition=`transform ${this.options.transitionDuration}ms ease`;this.bindEvents();this.update();if(this.options.autoplay){this.startAutoplay()}let resizeTimeout;this.resizeHandler=()=>{clearTimeout(resizeTimeout);resizeTimeout=setTimeout(()=>{this._setSlidesStyle();this.update()},100)};window.addEventListener("resize",this.resizeHandler)}bindEvents(){this.handlerPrev=()=>this.prevSlide();this.handlerNext=()=>this.nextSlide();this.prevBtn?.addEventListener("click",this.handlerPrev);this.nextBtn?.addEventListener("click",this.handlerNext);this.dots.forEach((dot,index)=>{const handler=()=>{if(this.options.loop){this.goToSlide(index+this.options.items)}else{this.goToSlide(index)}};this.dotHandlers.push(handler);dot.addEventListener("click",handler)});this.transitionEndHandler=e=>{if(e.propertyName!=="transform")return;this.isAnimating=false;if(!this.options.loop)return;const items=this.options.items;const totalSlides=this.slides.length;if(this.index>=totalSlides-items){this.track.style.transition="none";this.index=items;this.update();setTimeout(()=>{this.track.style.transition=`transform ${this.options.transitionDuration}ms ease`},0)}if(this.index<items){this.track.style.transition="none";this.index=totalSlides-items*2;this.update();setTimeout(()=>{this.track.style.transition=`transform ${this.options.transitionDuration}ms ease`},0)}};this.track.addEventListener("transitionend",this.transitionEndHandler)}_setSlidesStyle(){const percent=100/this.options.items;this.track.style.display="flex";this.slides.forEach(slide=>{slide.style.flex=`0 0 ${percent}%`})}update(){const slideWidth=100/this.options.items;this.track.style.transform=`translateX(-${this.index*slideWidth}%)`;this.updateDots()}updateDots(){if(!this.dots.length)return;this.dots.forEach(dot=>dot.classList.remove("active"));let realIndex=this.index;if(this.options.loop){realIndex=this.index-this.options.items;if(realIndex<0){realIndex=this.dots.length-1}if(realIndex>=this.dots.length){realIndex=0}}if(realIndex>=this.dots.length)return;this.dots[realIndex]?.classList.add("active")}_setupCloneSlides(){const items=this.options.items;const slideArray=Array.from(this.slides);const fragmentStart=document.createDocumentFragment();const fragmentEnd=document.createDocumentFragment();for(let i=slideArray.length-items;i<slideArray.length;i++){const clone=slideArray[i].cloneNode(true);fragmentStart.appendChild(clone)}for(let i=0;i<items;i++){const clone=slideArray[i].cloneNode(true);fragmentEnd.appendChild(clone)}this.track.insertBefore(fragmentStart,this.slides[0]);this.track.appendChild(fragmentEnd);this.slides=this.container.querySelectorAll(".slidezy-slide");this.index=items}nextSlide(){if(this.isAnimating)return;const maxIndex=this.slides.length-this.options.items;if(!this.options.loop&&this.index>=maxIndex)return;this.isAnimating=true;if(this.options.loop){this.index+=this.options.step}else{this.index=Math.min(this.index+this.options.step,maxIndex)}this.update()}prevSlide(){if(this.isAnimating)return;if(!this.options.loop&&this.index<=0)return;this.isAnimating=true;if(this.options.loop){this.index-=this.options.step}else{this.index=Math.max(this.index-this.options.step,0)}this.update()}goToSlide(index){if(this.isAnimating)return;this.isAnimating=true;if(this.options.loop){if(index>=0&&index<this.slides.length){this.index=index;this.update()}}else{const maxIndex=this.slides.length-this.options.items;if(index>=0&&index<=maxIndex){this.index=index;this.update()}}}startAutoplay(){this.stopAutoplay();if(this.options.autoplay){this.timer=setInterval(()=>this.nextSlide(),this.options.slideDuration)}}stopAutoplay(){clearInterval(this.timer);this.timer=null}destroy(){this.prevBtn?.removeEventListener("click",this.handlerPrev);this.nextBtn?.removeEventListener("click",this.handlerNext);this.dots.forEach((dot,index)=>{dot.removeEventListener("click",this.handlerDots[index])});this.track.removeEventListener("transitionend",this.transitionEndHandler);window.removeEventListener("resize",this.resizeHandler);this.stopAutoplay()}}const slidezy=new Slidezy("#mySlider",{slideDuration:4e3,transitionDuration:600,autoplay:false,loop:true,items:3,step:2});